const input = $input.first().json;
const job = input.job;
const jd = input.jd_intelligence;
const ctx = input.ctx;
const resume = ctx.results.resume_profile;
const career = ctx.results.career_goals;

// Extract vectors if passed. If OpenAI fails, these will be missing or mock fallback applies.
const semanticFallback = !input.vector_score;
let semanticScore = semanticFallback ? null : input.vector_score * 100;

// 1. Skill Match (30 points)
const resumeSkills = (resume.skills_matrix || []).map(s => s.normalized.toLowerCase());
const jdMandatory = jd.mandatory_skills || [];
const missingMandatory = [];
let skillMatchCount = 0;

jdMandatory.forEach(skill => {
  if (resumeSkills.includes(skill.toLowerCase())) {
    skillMatchCount++;
  } else {
    missingMandatory.push(skill);
  }
});
const skillScore = jdMandatory.length === 0 ? 30 : Math.round((skillMatchCount / jdMandatory.length) * 30);

// 2. Experience Match (20 points)
const jdExp = jd.required_years_experience || 0;
const resExp = career.total_years_experience || 0;
let expScore = 20;
let expGap = 0;
if (resExp < jdExp) {
  expScore = Math.max(0, 20 - ((jdExp - resExp) * 5));
  expGap = jdExp - resExp;
}

// 3. Keyword Match (15 points)
const jdKeywords = jd.domain_keywords || [];
const missingKeywords = [];
let kwMatchCount = 0;
jdKeywords.forEach(kw => {
  if (resumeSkills.includes(kw.toLowerCase()) || JSON.stringify(resume).toLowerCase().includes(kw.toLowerCase())) {
    kwMatchCount++;
  } else {
    missingKeywords.push(kw);
  }
});
const keywordScore = jdKeywords.length === 0 ? 15 : Math.round((kwMatchCount / jdKeywords.length) * 15);

// 4. Semantic Match (25 points) or Deterministic Fallback if Semantic failed
let finalSemanticWeight = 25;
let computedSemanticScore = 0;
if (semanticFallback) {
  // If OpenAI failed, reallocate the 25 points based purely on Title match and pure Keyword presence
  const titleMatch = job.title.toLowerCase().includes((career.inferred_roles?.[0] || '').toLowerCase());
  computedSemanticScore = titleMatch ? 15 : 0;
  computedSemanticScore += (keywordScore / 15) * 10; 
} else {
  computedSemanticScore = Math.round((semanticScore / 100) * 25);
}

// 5. Formatting/Quality (10 points)
const qualityScore = Math.round(((resume.quality_report?.score || 100) / 100) * 10);

const overallScore = Math.min(100, skillScore + expScore + keywordScore + computedSemanticScore + qualityScore);

// Readiness classification
let readiness = 'LOW';
if (overallScore >= 80) readiness = 'HIGH';
else if (overallScore >= 60) readiness = 'MEDIUM';

const evaluation = {
  overall_score: overallScore,
  section_scores: {
    skills: skillScore,
    experience: expScore,
    keywords: keywordScore,
    semantic: semanticFallback ? null : Math.round(semanticScore),
    semantic_fallback_used: semanticFallback
  },
  hiring_readiness: readiness,
  gap_analysis: {
    missing_mandatory_skills: missingMandatory,
    missing_preferred_skills: [], // To be populated if needed
    missing_keywords: missingKeywords,
    experience_gap_years: expGap
  }
};

// Prepare Prompt for LLM Recommendations
const prompt = `Candidate ATS Score: ${overallScore}/100.\nMissing Mandatory Skills: ${missingMandatory.join(', ')}.\nMissing Keywords: ${missingKeywords.join(', ')}.\nRecommend optimization strategies.`;

return [{
  json: {
    job,
    evaluation,
    prompt,
    model: $env.MODEL_ATS_RECOMMENDATION || 'anthropic/claude-haiku-3'
  }
}];

