const req = $('Deterministic Scoring').item.json;
const llmRes = $input.first().json;

let recommendations = [];
let strategy = 'MINOR_CHANGES';

if (llmRes.choices && llmRes.choices.length > 0) {
  try {
    const parsed = JSON.parse(llmRes.choices[0].message.content);
    recommendations = parsed.optimization_recommendations || [];
    strategy = parsed.strategy || strategy;
  } catch (e) {}
}

req.evaluation.optimization_recommendations = recommendations;
req.evaluation.strategy = strategy;

return [{ json: { job: req.job, ats_evaluation: req.evaluation } }];
